5043	\section{Projective space, the Serre twist, and projective morphisms}
5044	\label{sec:projective_vocabulary}
5045	
5046	Representability of the Quot functor holds for a \emph{projective} structural
5047	morphism carrying a relatively very ample line bundle
5048	([Nitsure] \S 5); properness alone does not suffice.  This
5049	section builds the ambient vocabulary: relative projective space, the Serre
5050	twisting sheaf, and the projective-morphism predicate together with its
5051	stability properties.
5052	% ENCODING. Formalized in AlgebraicJacobian/Picard/ProjectiveSpace.lean,
5053	% SerreTwist.lean, ProjectiveMorphism.lean (T14; inbox I-0118 encoding (a)).
5054	% The Serre twist rests on the module descent engine Scheme.Modules.glue,
5055	% which is universe-monomorphic at Scheme.GlueData.{0}; the twist, the
5056	% predicate and its stability facts are therefore stated for Scheme.{0}.
5057	
5058	\begin{definition}
5059	[Relative projective space]
5060	  \label{def:projective_space}
5061	  \leanok
5062	  \lean{AlgebraicGeometry.ProjectiveSpace}
5063	  \source{nitsure-hilbert-quot}
5064	  Let \(S\) be a scheme and let \(n\) be an index set.  The \emph{relative
5065	  projective space} \(\mathbb{P}(n; S)\) is the fibre product
5066	  \[
5067	    \mathbb{P}(n; S) \;=\; S \times_{\operatorname{Spec} \mathbb{Z}}
5068	      \operatorname{Proj} \mathbb{Z}[X_i : i \in n],
5069	  \]
5070	  where the polynomial ring carries the total-degree grading.  Its
5071	  \emph{structural morphism} \(\mathbb{P}(n; S) \to S\) is the first
5072	  projection.  For \(n = \{0, \dots, d\}\) this is the usual projective
5073	  \(d\)-space \(\mathbb{P}^d_S\).
5074	\end{definition}
5075	
5076	\begin{lemma}
5077	[Degree-zero part of the homogeneous coordinate ring]
5078	  \label{lem:projective_space_gradeZero}
5079	  \leanok
5080	  \lean{AlgebraicGeometry.ProjectiveSpace.gradeZeroRingEquiv}
5081	  The degree-zero part of the total-degree grading on
5082	  \(\mathbb{Z}[X_i : i \in n]\) is the subring of constants: the structural
5083	  map \(\mathbb{Z} \to (\mathbb{Z}[X_i : i \in n])_0\) is a ring isomorphism.
5084	  Consequently \(\operatorname{Spec}\) of the degree-zero part is a terminal
5085	  scheme.
5086	\end{lemma}
5087	
5088	\begin{proof}
5089	  \leanok
5090	  A polynomial is homogeneous of degree \(0\) exactly when it is a constant,
5091	  so the degree-zero submodule is the image of \(\mathbb{Z}\) under the
5092	  (injective) constants map.
5093	\end{proof}
5094	
5095	\begin{lemma}
5096	[Properness of the integral model]
5097	  \label{lem:proj_toSpecZero_proper}
5098	  \mathlibok
5099	  \lean{AlgebraicGeometry.Proj.toSpecZero}
5100	  For a \(\mathbb{N}\)-graded ring \(A\) of finite type over its degree-zero
5101	  part \(A_0\), the structural morphism
5102	  \(\operatorname{Proj} A \to \operatorname{Spec} A_0\) is proper (separated,
5103	  universally closed, and of finite type).
5104	\end{lemma}
5105	
5106	\begin{lemma}
5107	[Properness of relative projective space]
5108	  \label{lem:projective_space_proper}
5109	  \leanok
5110	  \lean{AlgebraicGeometry.ProjectiveSpace.isProper_over}
5111	  \uses{def:projective_space, lem:projective_space_gradeZero,
5112	    lem:proj_toSpecZero_proper}
5113	  For a finite index set \(n\), the structural morphism
5114	  \(\mathbb{P}(n; S) \to S\) is proper (hence separated, universally closed,
5115	  quasi-compact, and locally of finite type).
5116	\end{lemma}
5117	
5118	\begin{proof}
5119	  \leanok
5120	  \uses{lem:projective_space_gradeZero, lem:proj_toSpecZero_proper}
5121	  For finite \(n\), the polynomial ring \(\mathbb{Z}[X_i : i \in n]\) is of
5122	  finite type over its degree-zero part, which is \(\mathbb{Z}\) by
5123	  \Cref{lem:projective_space_gradeZero}; hence the integral model
5124	  \(\operatorname{Proj} \mathbb{Z}[X_i]\) is proper over
5125	  \(\operatorname{Spec} \mathbb{Z}\) by \Cref{lem:proj_toSpecZero_proper},
5126	  which is the terminal scheme.  Properness is stable under base change, and
5127	  the structural morphism of \(\mathbb{P}(n; S)\) is the base change of
5128	  \(\operatorname{Proj} \mathbb{Z}[X_i] \to \operatorname{Spec} \mathbb{Z}\)
5129	  along \(S \to \operatorname{Spec} \mathbb{Z}\).
5130	\end{proof}
5131	
5132	\begin{lemma}
5133	[Base change of relative projective space]
5134	  \label{lem:projective_space_base_change}
5135	  \leanok
5136	  \lean{AlgebraicGeometry.ProjectiveSpace.isPullback_map}
5137	  \uses{def:projective_space}
5138	  For every morphism \(g : S' \to S\) the canonical square
5139	  \[
5140	    \begin{array}{ccc}
5141	      \mathbb{P}(n; S') & \longrightarrow & \mathbb{P}(n; S) \\
5142	      \downarrow & & \downarrow \\
5143	      S' & \xrightarrow{\;g\;} & S
5144	    \end{array}
5145	  \]
5146	  is cartesian.
5147	\end{lemma}
5148	
5149	\begin{proof}
5150	  \leanok
5151	  Both \(\mathbb{P}(n; S')\) and \(\mathbb{P}(n; S) \times_S S'\) are fibre
5152	  products of \(S' \to \operatorname{Spec}\mathbb{Z} \leftarrow
5153	  \operatorname{Proj} \mathbb{Z}[X_i]\), by the pasting law for cartesian
5154	  squares applied to the defining square of \(\mathbb{P}(n; S)\) over the
5155	  terminal scheme.
5156	\end{proof}
5157	
5158	\begin{lemma}
5159	[The transition units of the Serre twist]
5160	  \label{lem:serre_twist_transition_unit}
5161	  \leanok
5162	  \lean{AlgebraicGeometry.ProjTwist.awayUnit}
5163	  In the degree-zero part of the localization
5164	  \(\mathbb{Z}[X_i : i \in n]_{X_i X_j}\), the fraction
5165	  \(X_i/X_j = X_i^2/(X_i X_j)\) is a unit, with inverse
5166	  \(X_j/X_i = X_j^2/(X_i X_j)\).
5167	\end{lemma}
5168	
5169	\begin{proof}
5170	  \leanok
5171	  The product of the two fractions is
5172	  \(X_i^2 X_j^2 / (X_i X_j)^2 = 1\).
5173	\end{proof}
5174	
5175	\begin{lemma}
5176	[Cocycle property of the Serre-twist transitions]
5177	  \label{lem:serre_twist_cocycle}
5178	  \leanok
5179	  \lean{AlgebraicGeometry.ProjTwist.twistTransition_cocycle}
5180	  \uses{lem:serre_twist_transition_unit}
5181	  On \(\operatorname{Proj} \mathbb{Z}[X_i : i \in n]\), for each \(m \ge 0\)
5182	  the multiplication maps by \((X_i/X_j)^m\) on the trivial line bundles over
5183	  the basic opens \(D_+(X_i)\), transported to the pairwise scheme-theoretic
5184	  overlaps of the cover, satisfy the descent cocycle condition on triple
5185	  overlaps: over \(D_+(X_i) \cap D_+(X_j) \cap D_+(X_k)\),
5186	  \[
5187	    \left(\frac{X_j}{X_k}\right)^{m}
5188	    \left(\frac{X_i}{X_j}\right)^{m}
5189	    \;=\; \left(\frac{X_i}{X_k}\right)^{m},
5190	  \]
5191	  compatibly with the identifications of the restricted trivial bundles.
5192	\end{lemma}
5193	
5194	\begin{proof}
5195	  \uses{lem:serre_twist_transition_unit}
5196	  In the degree-zero part of the localization
5197	  \(\mathbb{Z}[X_i]_{X_i X_j X_k}\), the three fractions satisfy
5198	  \((X_i/X_j)(X_j/X_k) = X_i/X_k\) since
5199	  \(X_i^2 X_j^2 X_k^2 = (X_i X_j)(X_j X_k)(X_i X_k)\); raising to the
5200	  \(m\)-th power preserves the identity.  The multiplication maps by these
5201	  units on the trivial line bundles commute with restriction to smaller
5202	  opens, because multiplication by a section commutes with the restriction
5203	  maps of the structure sheaf; and the trivialization comparisons between
5204	  the restricted bundles compose transitively.  Hence the transported
5205	  transition isomorphisms compose as claimed.
5206	\end{proof}
5207	
5208	\begin{definition}
5209	[The Serre twisting sheaf on the integral model]
5210	  \label{def:serre_twist}
5211	  \leanok
5212	  \lean{AlgebraicGeometry.ProjTwist.serreTwist}
5213	  \uses{lem:serre_twist_transition_unit, lem:serre_twist_cocycle}
5214	  \source{nitsure-hilbert-quot}
5215	  % STATUS. The definition compiles; the sole unformalized ingredient of its
5216	  % cone is the proof of lem:serre_twist_cocycle
5217	  % (AlgebraicGeometry.ProjTwist.twistTransition_cocycle, a named `sorry` in
5218	  % SerreTwist.lean), so declarations mentioning the twist are not yet
5219	  % axiom-clean.  The glued object does not consume the cocycle proof
5220	  % mathematically — it enters only through the effective-descent
5221	  % (restriction) isomorphisms.
5222	  For \(m \ge 0\), the \emph{Serre twisting sheaf} \(\mathcal{O}(m)\) on
5223	  \(\operatorname{Proj} \mathbb{Z}[X_i : i \in n]\) is the sheaf of modules
5224	  glued from the trivial line bundles \(\mathcal{O}_{D_+(X_i)}\) on the
5225	  basic opens of the standard affine cover along the transition
5226	  isomorphisms ``multiplication by \((X_i/X_j)^m\)'' of
5227	  \Cref{lem:serre_twist_transition_unit}, which satisfy the descent cocycle
5228	  condition by \Cref{lem:serre_twist_cocycle}.
5229	\end{definition}
5230	
5231	\begin{definition}
5232	[The Serre twist on relative projective space]
5233	  \label{def:twisting_sheaf}
5234	  \leanok
5235	  \lean{AlgebraicGeometry.ProjectiveSpace.twistingSheaf}
5236	  \uses{def:projective_space, def:serre_twist}
5237	  The \emph{Serre twist} \(\mathcal{O}(m)\) on \(\mathbb{P}(n; S)\) is the
5238	  pullback of the twisting sheaf of \Cref{def:serre_twist} along the
5239	  projection \(\mathbb{P}(n; S) \to \operatorname{Proj} \mathbb{Z}[X_i]\).
5240	\end{definition}
5241	
5242	\begin{lemma}
5243	[Base change of the Serre twist]
5244	  \label{lem:twisting_sheaf_base_change}
5245	  \leanok
5246	  \lean{AlgebraicGeometry.ProjectiveSpace.twistingSheafBaseChange}
5247	  \uses{def:twisting_sheaf, lem:projective_space_base_change}
5248	  For \(g : S' \to S\), the pullback of \(\mathcal{O}(m)\) on
5249	  \(\mathbb{P}(n; S)\) along the base-change morphism
5250	  \(\mathbb{P}(n; S') \to \mathbb{P}(n; S)\) is canonically isomorphic to
5251	  \(\mathcal{O}(m)\) on \(\mathbb{P}(n; S')\).
5252	\end{lemma}
5253	
5254	\begin{proof}
5255	  \leanok
5256	  Both sheaves are pullbacks of the twisting sheaf on the integral model,
5257	  along the two legs of the commuting triangle formed by the base-change
5258	  morphism and the two projections to
5259	  \(\operatorname{Proj} \mathbb{Z}[X_i]\).
5260	\end{proof}
5261	
5262	\begin{definition}
5263	[Projective morphism carrying a very ample line bundle]
5264	  \label{def:projective_with}
5265	  \leanok
5266	  \lean{AlgebraicGeometry.Scheme.Hom.IsProjectiveWith}
5267	  \uses{def:projective_space, def:twisting_sheaf}
5268	  \source{nitsure-hilbert-quot}
5269	  A morphism of schemes \(\pi : X \to S\) is \emph{projective carrying the
5270	  line bundle \(L\)} if there are \(d \ge 0\) and a closed immersion
5271	  \(i : X \hookrightarrow \mathbb{P}(\{0,\dots,d\}; S)\) over \(S\) with
5272	  \(L \cong i^* \mathcal{O}(1)\).  In this situation \(L\) is relatively
5273	  very ample and \(\pi\) is projective in the sense of [Nitsure] \S 5.
5274	\end{definition}
5275	
5276	\begin{lemma}
5277	[Projective morphisms are proper]
5278	  \label{lem:projective_with_proper}
5279	  \leanok
5280	  \lean{AlgebraicGeometry.Scheme.Hom.IsProjectiveWith.isProper}
5281	  \uses{def:projective_with, lem:projective_space_proper}
5282	  A projective morphism carrying a line bundle is proper.
5283	\end{lemma}
5284	
5285	\begin{proof}
5286	  \leanok
5287	  \uses{lem:projective_space_proper}
5288	  A closed immersion is proper, the structural morphism of projective space
5289	  is proper (\Cref{lem:projective_space_proper}), and properness is stable
5290	  under composition.
5291	\end{proof}
5292	
5293	\begin{lemma}
5294	[Composition with closed immersions]
5295	  \label{lem:projective_with_closed_immersion}
5296	  \leanok
5297	  \lean{AlgebraicGeometry.Scheme.Hom.IsProjectiveWith.comp_isClosedImmersion}
5298	  \uses{def:projective_with}
5299	  If \(\pi : X \to S\) is projective carrying \(L\) and \(j : Y \to X\) is a
5300	  closed immersion, then \(\pi \circ j\) is projective carrying \(j^* L\).
5301	\end{lemma}
5302	
5303	\begin{proof}
5304	  \leanok
5305	  Compose the given closed immersion \(i : X \hookrightarrow
5306	  \mathbb{P}(\{0,\dots,d\}; S)\) with \(j\): a composite of closed
5307	  immersions is a closed immersion, the triangle over \(S\) still commutes,
5308	  and \(j^* L \cong j^* i^* \mathcal{O}(1) \cong (i \circ j)^*
5309	  \mathcal{O}(1)\).
5310	\end{proof}
5311	
5312	\begin{lemma}
5313	[Base change of projective morphisms]
5314	  \label{lem:projective_with_base_change}
5315	  \leanok
5316	  \lean{AlgebraicGeometry.Scheme.Hom.IsProjectiveWith.baseChange}
5317	  \uses{def:projective_with, lem:projective_space_base_change,
5318	    lem:twisting_sheaf_base_change}
5319	  If \(\pi : X \to S\) is projective carrying \(L\) and \(g : S' \to S\) is
5320	  any morphism, then the base change \(X \times_S S' \to S'\) is projective
5321	  carrying the pullback of \(L\) along \(X \times_S S' \to X\).
5322	\end{lemma}
5323	
5324	\begin{proof}
5325	  \leanok
5326	  \uses{lem:projective_space_base_change, lem:twisting_sheaf_base_change}
5327	  Base-change the closed immersion \(i\) along
5328	  \(\mathbb{P}(\{0,\dots,d\}; S') \to \mathbb{P}(\{0,\dots,d\}; S)\)
5329	  (\Cref{lem:projective_space_base_change}): closed immersions are stable
5330	  under base change, the induced comparison morphism
5331	  \(X \times_S S' \to \mathbb{P}(\{0,\dots,d\}; S')\) lies over \(S'\), and
5332	  the pulled-back bundle is identified with \(\mathcal{O}(1)\) of the
5333	  base-changed projective space by \Cref{lem:twisting_sheaf_base_change}.
5334	\end{proof}
