5336	\section{Representability of the Quot scheme}
5337	\label{sec:quot_representable}
5338	
5339	\begin{theorem}\notready
5340	[Representability of the Quot functor]
5341	  \label{thm:quot_representable}
5342	  \lean{AlgebraicGeometry.Scheme.QuotScheme}
5343	  % LEAN/BLUEPRINT MISMATCH (see inbox I-0118): this statement carries the
5344	  % correct Nitsure hypotheses (\(\pi\) projective, \(L\) relatively very ample,
5345	  % \(E\) coherent).  The linked Lean \texttt{QuotScheme} instead hypothesizes
5346	  % only properness + locally-finite-type over arbitrary quasi-coherent \(L,E\)
5347	  % --- a strictly weaker, FALSE-as-pinned signature (Hironaka smooth-proper
5348	  % non-projective counterexample family; the functor is only an algebraic
5349	  % space).  Mathlib v4.31 lacks projectivity/very-ampleness vocabulary, so the
5350	  % Lean cannot yet faithfully formalize this statement; hence \notready, not
5351	  % \leanok, until the Lean signature is restated with projectivity.
5352	  \uses{def:quot_functor, lem:quot_boundedness, lem:quot_alpha_injective,
5353	    lem:quot_reduction_to_pi_star_W, lem:quot_valuative_criterion,
5354	    thm:grassmannian_representable, thm:flattening_stratification_exists,
5355	    thm:flat_base_change_cohomology}
5356	
5357	  % SOURCE: [Nitsure], \S 5, "Main Existence Theorems"
5358	  % (read from references/nitsure-hilbert-quot-src/nitsure-hilbert-quot.tex,
5359	  % L2220-L2273); cf.\ Grothendieck, FGA TDTE-IV.
5360	  % SOURCE QUOTE:
5361	  % "Let \(S\) be a noetherian scheme, \(\pi: X\to S\) a projective morphism,
5362	  %  and \(L\) a relatively very ample line bundle on \(X\). Then for any
5363	  %  coherent \({\mathcal O}_X\)-module \(E\) and any polynomial \(\Phi \in \Q[\lambda]\),
5364	  %  the functor \(\Quot_{E/X/S}^{\Phi,L}\) is representable
5365	  %  by a projective \(S\)-scheme \(\quot_{E/X/S}^{\Phi,L}\)."
5366	  \textit{Source: [Nitsure], \S 5, Theorem (Grothendieck), Theorem
5367	  (Altman--Kleiman) (FGA Explained Ch.~5); cf.\ Grothendieck, FGA TDTE-IV.}
5368	  Let \(S\) be a noetherian scheme, \(\pi : X \to S\) a projective morphism,
5369	  \(L\) a relatively very ample line bundle on \(X\), \(E\) a coherent
5370	  \(\mathcal{O}_X\)-module, and \(\Phi \in \mathbb{Q}[\lambda]\). Then the
5371	  functor \(\Quot^{\Phi,L}_{E/X/S}\) of \cref{def:quot_functor} is
5372	  representable by a projective \(S\)-scheme \(\Quot^{\Phi,L}_{E/X/S}\),
5373	  equipped with a universal quotient
5374	  \[
5375	    q^{\mathrm{univ}} :
5376	    \pi^*_{\Quot} E \twoheadrightarrow \mathcal{F}^{\mathrm{univ}}
5377	    \quad \text{on } X \times_S \Quot^{\Phi,L}_{E/X/S},
5378	  \]
5379	  flat over \(\Quot^{\Phi,L}_{E/X/S}\) with constant Hilbert polynomial
5380	  \(\Phi\) on every fiber. The Hilbert scheme is the special case
5381	  \(E = \mathcal{O}_X\): \(\Hilb^{\Phi,L}_{X/S} = \Quot^{\Phi,L}_{\mathcal{O}_X/X/S}\)
5382	  represents the functor of \(T\)-flat closed subschemes
5383	  \(Y \subset X_T\) with fiberwise Hilbert polynomial \(\Phi\).
5384	\end{theorem}
5385	
5386	% SOURCE QUOTE PROOF: this proof is long (~5 named sub-sections in [Nitsure]
5387	% \S 5). Each sub-step is recorded with its own SOURCE QUOTE in the
5388	% sub-lemmas below. The structural skeleton of the proof is restated in
5389	% project notation in the \begin{proof} block.
5390	\begin{proof}
5391	  
5392	  The proof has four steps; each step is a sub-lemma in the next
5393	  sub-sections.
5394	  \begin{enumerate}
5395	    \item \textbf{(Boundedness, \cref{lem:quot_boundedness}.)} Pick the
5396	      Castelnuovo--Mumford regularity bound \(m = m(\mathrm{rank}\,V,
5397	      \mathrm{rank}\,W, \Phi)\) uniformly across all fibers (by Mumford's
5398	      \(m\)-regularity theorem applied to \(E_s\) and to all coherent
5399	      quotients of \(E_s\) with Hilbert polynomial \(\Phi\)). For \(r \ge m\)
